    static class RateLimiter {
        private final long maxBytesPerSecond;
        private long lastRefillTime;
        private long availableTokens;

        public RateLimiter(long maxBytesPerSecond) {
            this.maxBytesPerSecond = maxBytesPerSecond;
            this.lastRefillTime = System.currentTimeMillis();
            this.availableTokens = maxBytesPerSecond;
        }

        public synchronized boolean tryAcquire(long bytes) {
            refill();
            
            if (availableTokens >= bytes) {
                availableTokens -= bytes;
                return true;
            }
            return false;
        }

        private void refill() {
            long now = System.currentTimeMillis();
            long timePassed = now - lastRefillTime;
            
            if (timePassed > 0) {
                long tokensToAdd = (timePassed * maxBytesPerSecond) / 1000;
                availableTokens = Math.min(maxBytesPerSecond, availableTokens + tokensToAdd);
                lastRefillTime = now;
            }
        }
    }

